import{_ as o,o as i,c as a,ae as l}from"./chunks/framework.B9bl8Hm5.js";const _=JSON.parse('{"title":"JavaScript 知识点","description":"","frontmatter":{},"headers":[],"relativePath":"javascript.md","filePath":"javascript.md"}'),c={name:"javascript.md"};function d(t,e,r,n,s,h){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="javascript-知识点" tabindex="-1">JavaScript 知识点 <a class="header-anchor" href="#javascript-知识点" aria-label="Permalink to &quot;JavaScript 知识点&quot;">​</a></h1><h2 id="_1-数据类型" tabindex="-1">1. 数据类型 <a class="header-anchor" href="#_1-数据类型" aria-label="Permalink to &quot;1. 数据类型&quot;">​</a></h2><ul><li>基本数据类型：<code>Number</code>, <code>String</code>, <code>Boolean</code>, <code>Null</code>, <code>Undefined</code>, <code>Symbol</code>, <code>BigInt</code></li><li>引用数据类型：<code>Object</code>（包括 <code>Array</code>, <code>Function</code>, <code>Date</code> 等）</li><li>类型判断：<code>typeof</code>, <code>instanceof</code>, <code>Object.prototype.toString.call()</code></li></ul><h2 id="_2-作用域" tabindex="-1">2. 作用域 <a class="header-anchor" href="#_2-作用域" aria-label="Permalink to &quot;2. 作用域&quot;">​</a></h2><ul><li>全局作用域</li><li>函数作用域</li><li>块级作用域（ES6+）：<code>let</code>, <code>const</code> 声明的变量</li></ul><h2 id="_3-闭包" tabindex="-1">3. 闭包 <a class="header-anchor" href="#_3-闭包" aria-label="Permalink to &quot;3. 闭包&quot;">​</a></h2><ul><li>定义：函数能够访问其外部作用域的变量</li><li>应用：模块化、私有变量、柯里化等</li><li>注意：可能导致内存泄漏</li></ul><h2 id="_4-this-指向" tabindex="-1">4. this 指向 <a class="header-anchor" href="#_4-this-指向" aria-label="Permalink to &quot;4. this 指向&quot;">​</a></h2><ul><li>全局上下文：指向 <code>window</code>（浏览器）或 <code>global</code>（Node.js）</li><li>函数调用：指向调用函数的对象</li><li>构造函数：指向新创建的实例</li><li><code>apply</code>, <code>call</code>, <code>bind</code>：改变 <code>this</code> 指向</li><li>箭头函数：继承外层作用域的 <code>this</code></li></ul><h2 id="_5-原型与原型链" tabindex="-1">5. 原型与原型链 <a class="header-anchor" href="#_5-原型与原型链" aria-label="Permalink to &quot;5. 原型与原型链&quot;">​</a></h2><ul><li>原型：每个函数都有 <code>prototype</code> 属性</li><li>原型链：对象通过 <code>__proto__</code> 指向其原型，形成链式结构</li><li>继承：基于原型链实现</li></ul><h2 id="_6-异步编程" tabindex="-1">6. 异步编程 <a class="header-anchor" href="#_6-异步编程" aria-label="Permalink to &quot;6. 异步编程&quot;">​</a></h2><ul><li>回调函数</li><li>Promise</li><li>async/await</li><li>事件循环（Event Loop）</li></ul><h2 id="_7-es6-新特性" tabindex="-1">7. ES6+ 新特性 <a class="header-anchor" href="#_7-es6-新特性" aria-label="Permalink to &quot;7. ES6+ 新特性&quot;">​</a></h2><ul><li>箭头函数</li><li>解构赋值</li><li>模板字符串</li><li>扩展运算符</li><li>模块化（<code>import</code>, <code>export</code>）</li><li>类（<code>class</code>）</li><li>生成器（<code>function*</code>）</li><li>Set 和 Map 数据结构</li></ul><h2 id="_8-数组方法" tabindex="-1">8. 数组方法 <a class="header-anchor" href="#_8-数组方法" aria-label="Permalink to &quot;8. 数组方法&quot;">​</a></h2><ul><li>遍历：<code>forEach</code>, <code>map</code>, <code>filter</code>, <code>reduce</code>, <code>some</code>, <code>every</code></li><li>操作：<code>push</code>, <code>pop</code>, <code>shift</code>, <code>unshift</code>, <code>splice</code>, <code>slice</code></li><li>其他：<code>join</code>, <code>concat</code>, <code>indexOf</code>, <code>includes</code></li></ul><h2 id="_9-防抖与节流" tabindex="-1">9. 防抖与节流 <a class="header-anchor" href="#_9-防抖与节流" aria-label="Permalink to &quot;9. 防抖与节流&quot;">​</a></h2><ul><li>防抖：多次触发，只执行最后一次</li><li>节流：一段时间内只执行一次</li><li>应用场景：搜索输入、滚动事件等</li></ul><h2 id="_10-深拷贝与浅拷贝" tabindex="-1">10. 深拷贝与浅拷贝 <a class="header-anchor" href="#_10-深拷贝与浅拷贝" aria-label="Permalink to &quot;10. 深拷贝与浅拷贝&quot;">​</a></h2><ul><li>浅拷贝：复制引用，修改会影响原对象</li><li>深拷贝：复制值，修改不会影响原对象</li><li>实现方式：<code>JSON.parse(JSON.stringify())</code>, 递归拷贝等</li></ul>',21)])])}const p=o(c,[["render",d]]);export{_ as __pageData,p as default};
